angular.module("RA.IPDisplay").directive("raIpLayoutPlanner", [ "layoutWidgetPlannerSvc", "$timeout", "DISPLAY_EVENTS", "CONTROLS_LAYOUT", function(layoutWidgetPlannerSvc, $timeout, DISPLAY_EVENTS, CONTROLS_LAYOUT) {
    "use strict";
    return {
        restrict: "E",
        link: function(scope, element, attrs) {
            element.addClass("layout-planner");
            var ratio = 1;
            var minHeight, minWidth;
            if (attrs.alignment) {
                if (attrs.alignment === "left") {
                    element.css("text-align", "left");
                } else if (attrs.alignment === "right") {
                    element.css("text-align", "right");
                }
            }
            function getSize(w, h, childrenCount, ratio) {
                var size = layoutWidgetPlannerSvc.countOptimalSize(w, h, childrenCount, ratio);
                size[0] -= CONTROLS_LAYOUT.WIDGET_PADDING * 2;
                size[1] -= CONTROLS_LAYOUT.WIDGET_PADDING * 2;
                return size;
            }
            scope.initAttrs = function() {
                // Use element.attr are not updated when changed
                if (element.attr("ratio")) {
                    ratio = parseFloat(element.attr("ratio"));
                }
                if (element.attr("minWidth")) {
                    minWidth = parseInt(element.attr("minWidth"));
                }
                if (element.attr("minHeight")) {
                    minHeight = parseInt(element.attr("minHeight"));
                }
            };
            scope.resize = function() {
                scope.initAttrs();
                $timeout(function() {
                    var w = element.width() - 1;
                    var h = element.height() - 1;
                    var childrenCount = element.children().length;
                    var size = getSize(w, h, childrenCount, ratio);
                    var tmpRatio = ratio;
                    /**
                         * if minimal height is specified, minimal width is ignored
                         */
                    if (minHeight) {
                        while (size[1] < minHeight && tmpRatio > 0) {
                            size = getSize(w, h, childrenCount, tmpRatio);
                            if (tmpRatio > 1) {
                                tmpRatio -= 1;
                            } else {
                                break;
                            }
                        }
                    } else if (minWidth) {
                        //At first we want to try to find the ration lower than 1
                        while (size[0] < minWidth && 1 / tmpRatio < 1) {
                            size = getSize(w, h, childrenCount, tmpRatio);
                            tmpRatio = 1 / (1 / tmpRatio - 1);
                        }
                        //If the ratio was not found we try to use ratio equal to 1;
                        if (size[0] < minWidth) {
                            tmpRatio = 1;
                            size = getSize(w, h, childrenCount, tmpRatio);
                            tmpRatio = 1.5;
                        }
                        //Then we try ratio 1.5 and going higher up to 5 (incrementing by 1)
                        while (size[0] < minWidth && tmpRatio < 5) {
                            size = getSize(w, h, childrenCount, tmpRatio);
                            tmpRatio += 1;
                        }
                    }
                    element.children().each(function(index, value) {
                        var child = angular.element(value);
                        child.outerWidth(size[0] + CONTROLS_LAYOUT.WIDGET_PADDING * 2);
                        child.outerHeight(size[1] + CONTROLS_LAYOUT.WIDGET_PADDING * 2);
                    });
                    scope.$broadcast(DISPLAY_EVENTS.WIDGET_WRAPPER_RESIZE, size);
                }, 200);
            };
            scope.resize();
            scope.$on(DISPLAY_EVENTS.CELL_RESIZE, function() {
                scope.resize();
            });
            scope.$watch(function() {
                return element.children().length;
            }, function(newVal, oldVal) {
                if (newVal !== oldVal) {
                    scope.resize();
                }
            });
            element.on("$destroy", function() {
                scope.$destroy();
            });
        }
    };
} ]);

