                    if (prevElem.timeStamp.getTime() > currentExtremes.min) {
                        // insert unknown from the beginning
                        tData.push(getChartElement(seriesList, dummyFirstItemState.name, currentExtremes.min, prevElem.timeStamp.getTime(), dummyFirstItemState.color, !showUnknownLegend && dummyFirstItemState.name === "Unknown"));
                    }
