/* global angular */
angular.module("RA.IPDisplay").service("escapeHTMLSvc", [ function() {
    "use strict";
    var tagsToReplace = {
        "&": "&amp;",
        "<": "&lt;",
        ">": "&gt;"
    };
    /**
         * Callback function which replace html tag or return original
         * (for case when regex and object differ thanks to human error)
         * @param {String} tag which should be replaced
         * @returns {String} processed tag
         */
    function replaceTag(tag) {
        return tagsToReplace[tag] || tag;
    }
    /**
         * Sanitize strings that might contain HTML tags
         * Callback function is used because it is faster than
         * call replace multiple times and its more readable
         * @param {String} string to be sanitized
         * @returns {String} processed string
         */
    function safeReplaceTag(str) {
        return str.replace(/[&<>]/g, replaceTag);
    }
    return {
        safeReplaceTag: safeReplaceTag
    };
} ]);

/* global angular */
/* global saveAs*/
/**
 * @ngdoc service
 * @module RA.IPDisplay
 * @name RA.IPDisplay.service:exportDataSvc
 * @description Service which provides data export functionality to supported widgets.
 */
angular.module("RA.IPDisplay").factory("exportDataSvc", [ "$window", function($window) {
    "use strict";
    var MAX_ALLOWED_DATA_COUNT_PC = 225e3, MAX_ALLOWED_DATA_COUNT_MOBILE = 15e3, MAX_ALLOWED_DATA_COUNT = isMobile() ? MAX_ALLOWED_DATA_COUNT_MOBILE : MAX_ALLOWED_DATA_COUNT_PC;
    function isMobile() {
        return /Android|webOS|iPhone|iPad|iPod|BlackBerry|IEMobile|Opera Mini/i.test($window.navigator.userAgent);
    }
    /**
         * Exports string data into csv file. Data should be formatted correctly first.
         * @param stringOutput
         */
    function exportData(stringOutput) {
        var blob = new Blob([ stringOutput ], {
            type: "text/plain;charset=utf-8"
        });
        saveAs(blob, "report.csv");
    }
    /**
         * Format is controlled by parameter "propertiesNames" which defines properties
         * to be exported. Header names should naturally correspond to properties names,
         * at least to some degree.
         * @param {Array} preparedData
         * @param headerNames
         * @param propertiesNames
         */
    function transformPreparedDataForExport(preparedData, headerNames, propertiesNames) {
        // header first
        var stringOut = '"' + headerNames.join('","') + '"\n';
        // append data to string
        angular.forEach(preparedData, function(entry) {
            stringOut += flatLine(entry, propertiesNames);
        });
        return stringOut;
    }
    /**
         * @param {Object} timeSeriesData
         * @param {Array} headerNames
         * @param {Array} propertiesNames
         * @returns {string}
         */
    function transformDataForExportNarrow(timeSeriesData, headerNames, propertiesNames) {
        return transformPreparedDataForExport(flatten(timeSeriesData).sort(sortByTimeStampsAndNames), headerNames, propertiesNames);
    }
    /**
         * Export in wide format is defined by the format of received data.
         * Use this method when working with data received directly from instance service.
         * @param {Object} timeSeriesData
         * @param {Array} headerNames - optional parameter used only for header
         * @returns {string}
         */
    function transformDataForExportWide(timeSeriesData, headerNames) {
        var propertiesNames = Object.keys(timeSeriesData).sort(), wideFormatHeader, all = flatten(timeSeriesData).sort(sortByTimeStampsAndNames), newLine, lines = [], stringOut;
        if (angular.isDefined(headerNames)) {
            wideFormatHeader = '"' + headerNames.join('","') + '"\n';
        } else {
            wideFormatHeader = '"DateTime","' + propertiesNames.join('","') + '"\n';
        }
        stringOut = wideFormatHeader;
        propertiesNames.unshift("timeStamp");
        // group into line objects by the means of time stamps
        newLine = {
            timeStamp: all[0].timeStamp
        };
        for (var i = 0; i < all.length; ++i) {
            if (!angular.equals(all[i].timeStamp, newLine.timeStamp)) {
                lines.push(newLine);
                newLine = {
                    timeStamp: all[i].timeStamp
                };
            }
            newLine[all[i].name] = all[i].value;
        }
        // last item does not enter the for loop again
        lines.push(newLine);
        // transform to string
        angular.forEach(lines, function(line) {
            stringOut += flatLine(line, propertiesNames);
        });
        return stringOut;
    }
    /**
         * Transforms time series data received from server. Puts all value
         * objects into a single array and also adds parameter "name" after
         * parent FQN.
         * @param {Object} timeSeriesData
         * @returns {Array} - all sorted and named value objects
         */
    function flatten(timeSeriesData) {
        var tagName, all = [];
        // flatten
        angular.forEach(timeSeriesData, function(series, name) {
            tagName = name;
            angular.forEach(series, function(item) {
                item.name = tagName;
                all.push(item);
            });
        });
        return all;
    }
    /**
         * Sorts value objects by time stamps and names as criteria respectively.
         * @param {Object} first
         * @param {Object} second
         * @returns {number}
         */
    function sortByTimeStampsAndNames(first, second) {
        if (angular.equals(first.timeStamp, second.timeStamp)) {
            return first.name > second.name ? 1 : -1;
        } else {
            return first.timeStamp > second.timeStamp ? 1 : -1;
        }
    }
    /**
         * Function to check for Date instance and apply conversion to UTC format.
         * @param {any} input 
         */
    function transformToString(input) {
        if (input instanceof Date) {
            return input.toISOString();
        }
        return input;
    }
    /**
         * Takes values of specified properties from given item and concatenates
         * them into a single line. Values are separated by comas. Line ends
         * with newline symbol.
         * @param {Object} item - contains values
         * @param {Array} keys - names of chosen properties
         * @returns {string} - line of values
         */
    function flatLine(item, keys) {
        var flattenedLine = "", increment;
        for (var i = 0, ln = keys.length - 1; i < ln; ++i) {
            if (angular.isDefined(item[keys[i]])) {
                increment = '"' + transformToString(item[keys[i]]) + '",';
            } else {
                increment = '"",';
            }
            flattenedLine += increment;
        }
        if (angular.isDefined(item[keys[i]])) {
            increment = '"' + transformToString(item[keys[i]]) + '"\n';
        } else {
            increment = '""\n';
        }
        flattenedLine += increment;
        return flattenedLine;
    }
    // Service API
    return {
        exportData: exportData,
        transformPreparedDataForExport: transformPreparedDataForExport,
        transformDataForExportNarrow: transformDataForExportNarrow,
        transformDataForExportWide: transformDataForExportWide,
        sortByTimeStampsAndNames: sortByTimeStampsAndNames,
        MAX_ALLOWED_DATA_COUNT: MAX_ALLOWED_DATA_COUNT
    };
} ]);

/* global angular */
/* jshint -W106 */
//API to gridstack does not use camelCase
