    /**
             * Count optimal size to fill window with same size rectangles
             * @returns {array} width and height of optimal rectangle
             */
    var countOptimalSize = function(width, height, N, ratio) {
        var resSize, xNum, yNum, size1, size2, maxSizeY, xPrefNum, yPrefNum;
        ratio = ratio === undefined ? 1 : ratio;
        maxSizeY = Math.sqrt(width * height / (N * ratio));
        if (N === 1 || N === 0) {
            return [ width, height ];
        }
        xPrefNum = width / (maxSizeY * ratio);
        yPrefNum = height / maxSizeY;
        if (xPrefNum > yPrefNum) {
            size1 = Math.floor(Math.floor(width / Math.ceil(N / Math.floor(yPrefNum))) / ratio);
            size2 = Math.floor(height / Math.ceil(yPrefNum));
            if (Math.floor(width / (size2 * ratio)) < Math.ceil(N / Math.ceil(yPrefNum))) {
                size2 = Math.floor(Math.floor(width / Math.ceil(N / Math.ceil(yPrefNum))) / ratio);
            } else {
                xPrefNum = 0;
            }
        } else {
            size1 = Math.floor(height / Math.ceil(N / Math.floor(xPrefNum)));
            size2 = Math.floor(Math.floor(width / Math.ceil(xPrefNum)) / ratio);
            if (Math.floor(height / size2) < Math.ceil(N / Math.ceil(xPrefNum))) {
                size2 = Math.floor(height / Math.ceil(N / Math.ceil(xPrefNum)));
            } else {
                yPrefNum = 0;
            }
        }
        // cover all space
        resSize = Math.max(size1, size2);
        if (xPrefNum > yPrefNum) {
            xNum = Math.floor(width / (resSize * ratio));
            xNum = xNum > N ? N : xNum;
            yNum = Math.ceil(N / xNum);
            return [ Math.floor(width / xNum), Math.floor(height / yNum) ];
        } else {
            yNum = Math.floor(height / resSize);
            yNum = yNum > N ? N : yNum;
            xNum = Math.ceil(N / yNum);
            return [ Math.floor(width / xNum), Math.floor(height / yNum) ];
        }
    };
