/**
 * @ngdoc service
 * @module RA.IPDisplay
 * @name RA.IPDisplay.service:querySvc
 * @description Service responsible for suporting Query Widget operations
 */
angular.module("RA.IPDisplay").factory("querySvc", [ "instanceSvc", "$q", "fqnSvc", function(instanceSvc, $q, fqnSvc) {
    "use strict";
    //Key in cache is in format "fqn;type"
    //Value in cache has format: 
    // {
    //     timestamp: number,
    //     lastUsed: number,
    //     response: object,
    //     key: string
    // }
    var cachedData = {};
    //maximum number of records in cache
    var maxCacheSize = 100;
    //Number of LRU records that should be deleted when the cache is full
    var deleteWhenFull = 20;
    //how long the cache record persist - in miliseconds
    var persistTime = 1e3 * 60 * 60;
    //list of now processing request keys
    var processingRequests = {};
    /**
     * Internal Method - Deletes Least Recently Used (LRU) Entry from cache
     * based on timestamp of last used
     */
    function deleteLRU() {
        var array = [];
        angular.forEach(cachedData, function(value) {
            array.push(value);
        });
        array.sort(function(a, b) {
            return a.lastUsed - b.lastUsed;
        });
        for (var i = 0; i < deleteWhenFull; i++) {
            delete cachedData[array[i].key];
        }
    }
    /**
     * Internal Method - Adds the query response to the cache 
     * in key, value pair format
     */
    function addNewItem(key, value) {
        var timestamp = Date.now();
        if (Object.keys(cachedData).length >= maxCacheSize) {
            deleteLRU();
        }
        cachedData[key] = {
            timestamp: timestamp,
            lastUsed: timestamp,
            response: value,
            key: key
        };
    }
    var typeQueryRequest = function(fqn, type, useCache, raPassError) {
        var deffered = $q.defer(), key, cachedItem;
        fqn = fqnSvc.buildFqnForQueryWithEscaping(fqn);
        key = fqn;
        if (Array.isArray(type)) {
            for (var i = 0; i < type.length; ++i) {
                key += ";" + type[i];
            }
        } else {
            key += ";" + type;
        }
        useCache = useCache === undefined ? true : useCache;
        cachedItem = cachedData[key];
        if (useCache && cachedItem && cachedItem.timestamp > Date.now() - persistTime) {
            cachedItem.lastUsed = Date.now();
            deffered.resolve(angular.copy(cachedItem.response));
        } else if (useCache && processingRequests[key]) {
            return processingRequests[key].promise;
        } else {
            //Item is too old or useCache is false
            if (cachedItem) {
                delete cachedData[key];
            }
            processingRequests[key] = {
                promise: deffered.promise
            };
            //WORKAROUND FOR B-83796 until VP will fix instance service query
            var parts = fqnSvc.splitFqn(fqn).length - 1;
            var depth = 8 - parts;
            if (depth < 6) {
                depth = 6;
            }
            var query = "FROM " + fqn + " TO DEPTH " + depth;
            if (Array.isArray(type)) {
                for (var j = 0; j < type.length; ++j) {
                    query += j === 0 ? " WHERE " : " or ";
                    query += "IsA(" + type[j] + ")";
                }
            } else {
                query += " WHERE IsA(" + type + ")";
            }
            var instanceRequest = instanceSvc.createInstanceRequest();
            instanceRequest.addQuery(query);
            instanceSvc.getInstances(instanceRequest, raPassError).then(function(result) {
                addNewItem(key, result);
                deffered.resolve(angular.copy(result));
                delete processingRequests[key];
            }, function(reason) {
                deffered.reject(reason);
            });
        }
        return deffered.promise;
    };
    var getRealInstances = function(queryResult, prop) {
        queryResult = angular.copy(queryResult);
        var deffered = $q.defer();
        var instanceRequest = instanceSvc.createInstanceRequest();
        angular.forEach(queryResult.data.queryResults[0], function(value) {
            var tmp = fqnSvc.relativeToAbsolute(value.fqn, prop);
            if (prop.length > 0) {
                instanceRequest.addPropertyFqn(tmp);
            } else {
                instanceRequest.addItemFqn(tmp);
            }
        });
        instanceSvc.getInstances(instanceRequest).then(function(result) {
            if (!result.data || !result.data.fqnsResults) {
                queryResult.data = {};
                queryResult.data.queryResults = [ [] ];
                deffered.resolve(queryResult);
            } else {
                for (var i = result.data.fqnsResults.length - 1; i >= 0; i--) {
                    if (result.data.fqnsResults[i].item === undefined && result.data.fqnsResults[i].value === undefined) {
                        queryResult.data.queryResults[0].splice(i, 1);
                    }
                }
                deffered.resolve(queryResult);
            }
        });
        return deffered.promise;
    };
    return {
        /**
         * @ngdoc method
         * @name RA.IPDisplay.service:querySvc#typeQueryRequest
         * @methodOf RA.IPDisplay.service:querySvc
         * @param {String} fqn FQN to use for Query
         * @param {String|Array} type Item Type of items to query for
         * @param {Boolean} useCache "true" if cahcing is to be used - default true
         * @param {Boolean} raPassError Parameter propagated into instanceSvc
         * @description Executes Type based Query request and returns results
         * @return {IPromise<T>} - Promise to resolve when answer
         * will be available.
         */
        typeQueryRequest: typeQueryRequest,
        /**
         * @ngdoc method
         * @name RA.IPDisplay.service:querySvc#getRealInstances
         * @methodOf RA.IPDisplay.service:querySvc
         * @param {Array} queryResult Results for Query with non-existance items included
         * @param {String} Property name to look for
         * @description Returns the queryResult object without non-existing instances
         * @return {IPromise<T>} - Promise to resolve when answer
         * will be available.
         */
        getRealInstances: getRealInstances
    };
} ]);

