/* global angular */
/**
 * @ngdoc service
 * @module RA.IPDisplay
 * @name RA.IPDisplay.service:schemaSvc
 * @description Service responsible for loading and dealing with widget schemas
 */
angular.module("RA.IPDisplay").provider("schemaSvc", function() {
    "use strict";
    this.$get = [ "widgetsConfigurationSvc", "widgetsConstantsSvc", function(widgetsConfigurationSvc, widgetsConstantsSvc) {
        var _injector, widgetSchemas = {};
        var loadedSchemas = null;
        _injector = {
            /**
                 * @ngdoc method
                 * @name RA.IPDisplay.service:schemaSvc#getSchemaTypePropertyName
                 * @methodOf RA.IPDisplay.service:schemaSvc
                 * @param {String} schema schema of the widget
                 * @description Gets schema type property name for given schema
                 * @return {String} schema type property name
                 */
            getSchemaTypePropertyName: function(schema) {
                var i, j, result = "";
                if (schema && schema.schema && schema.schema[0] && schema.schema[0].dropValue) {
                    return schema.schema[0].dropValue;
                }
                var checkChildSchema = function(child) {
                    var j, k, innerSchema, result;
                    if (child.type === "<schemaType>") {
                        return child.name;
                    }
                    if (child.type === "enum" && child.defaultValue) {
                        for (j = 0; j < child.enumValues.length; j++) {
                            if (child.defaultValue === child.enumValues[j].value) {
                                innerSchema = child.enumValues[j].innerSchema;
                                if (innerSchema) {
                                    for (k = 0; k < innerSchema.length; k++) {
                                        result = checkChildSchema(innerSchema[k]);
                                        if (result) {
                                            return result;
                                        }
                                    }
                                }
                            }
                        }
                    }
                    return "";
                };
                if (schema && schema.schema) {
                    for (i = 0; i < schema.schema.length; i++) {
                        for (j = 0; j < schema.schema[i].children.length; ++j) {
                            result = checkChildSchema(schema.schema[i].children[j]);
                            if (result) {
                                return result;
                            }
                        }
                    }
                }
                return result;
            },
            /**
                 * @ngdoc method
                 * @name RA.IPDisplay.service:schemaSvc#loadWidgetsSchema
                 * @methodOf RA.IPDisplay.service:schemaSvc
                 * @description Loads all available widget schemas into an array
                 * @return {Array} Array of schema(s) for all widgets
                 */
            loadWidgetsSchema: function() {
                var widgetSchema;
                if (loadedSchemas) {
                    return loadedSchemas;
                }
                if ($.isEmptyObject(widgetSchemas)) {
                    $.each(widgetsConfigurationSvc.getComposerComponents(), function(index, value) {
                        widgetSchema = widgetsConstantsSvc.getWidgetSchema(value.directive);
                        if (widgetSchema) {
                            widgetSchemas[value.directive] = widgetSchema;
                        }
                    });
                }
                loadedSchemas = widgetSchemas;
                return widgetSchemas;
            }
        };
        return _injector;
    } ];
});

/* global angular */
/**
 * @ngdoc service
 * @module RA.IPDisplay
 * @name RA.IPDisplay.service:styleSvc
 * @description Service responsible for adding custom css rules to the appended stylesheet.
 */
angular.module("RA.IPDisplay").factory("styleSvc", [ "colorTypeSvc", function(colorTypeSvc) {
    "use strict";
    var baseSelector = ".ra-dashboardStyleCustom-";
    var stylesheet = function() {
        var style = document.createElement("style");
        // WebKit hack
        style.appendChild(document.createTextNode(""));
        document.head.appendChild(style);
        return style.sheet;
    }();
    var applyStyles = function(style) {
        if (style && style.cellBackgroundColor) {
            applyStyle(baseSelector + "cell-background", "background-color", colorTypeSvc.getColorString(style.cellBackgroundColor));
        }
        if (style && style.dashboardBackgroundColor) {
            applyStyle(baseSelector + "dashboard-background", "background-color", colorTypeSvc.getColorString(style.dashboardBackgroundColor));
        }
    };
    var applyStyle = function(selector, property, value) {
        if (stylesheet.addRule) {
            stylesheet.addRule(selector, property + ":" + value);
        } else if (stylesheet.insertRule) {
            stylesheet.insertRule(selector + " { " + property + ":" + value + " }", stylesheet.cssRules.length);
        }
    };
    return {
        /**
                 * @ngdoc method
                 * @name RA.IPDisplay.service:styleSvc#applyStyles
                 * @methodOf RA.IPDisplay.service:styleSvc
                 * @param {Object} style Object containing **cellBackgroundColor** and **dashboardBackgroundColor**
                 * properties. These should contain any valid CSS color definition.
                 * @description Adds the custom CSS rule to DOM. It changes defintion of background-color property
                 * for **.ra-dashboardStyleCustom-dashboard-background** and
                 * **.ra-dashboardStyleCustom-cell-background** selectors.
                 */
        applyStyles: applyStyles
    };
} ]);

