/* global moment */
/**
 * @ngdoc service
 * @module RA.IPDisplay
 * @name RA.IPDisplay.service:timeseriesHelperSvc
 * @description Provides basic utilities for timeseries data.
 */
angular.module("RA.IPDisplay").service("timeseriesHelperSvc", [ function() {
    "use strict";
    function sortSeriesData(a, b) {
        return a.timeStamp.getTime() - b.timeStamp.getTime();
    }
    /**
         * Function to filter not needed data and duplicate data.
         * @param {Array} array to filter data from
         * @param {Moment} dateNowMinusDuration
         * @returns {Array} filtered array
         */
    function filterDataLocal(array, dateNowMinusDuration) {
        var ids = [], itemUnixTime, objectToAddToArray, firstIsAfter = false;
        function arrayFilter(o) {
            if (dateNowMinusDuration.isAfter(o.timeStamp)) {
                if (firstIsAfter === false) {
                    objectToAddToArray = angular.copy(o);
                    objectToAddToArray.timeStamp = dateNowMinusDuration.clone().toDate();
                    firstIsAfter = true;
                }
                return false;
            }
            itemUnixTime = o.timeStamp.getTime();
            if (ids.indexOf(itemUnixTime) !== -1) {
                return false;
            }
            ids.push(itemUnixTime);
            return true;
        }
        var filteredArray = array.reverse().filter(arrayFilter);
        if (firstIsAfter === true) {
            // it is reversed array so push to it
            filteredArray.push(objectToAddToArray);
        }
        return filteredArray.reverse();
    }
    /**
         * Function to filter data after specific time from array.
         * @param {Array} array
         * @param {Date} date date to cut data from
         * @returns {Array} filtered array
         */
    function cutAfterDate(array, date) {
        var dateUnixTime = date.getTime();
        function arrayFilter(o) {
            if (o.timeStamp.getTime() >= dateUnixTime) {
                return false;
            }
            return true;
        }
        return array.filter(arrayFilter);
    }
    /**
         * @description Function to calculate current end time minus duration
         * @param {Integer} dateTimeFrom date-time in unix miliseconds
         * @param {Integer} duration
         * @returns {Object} moment date object
         */
    function calculateTimeWithoutDuration(dateTimeFrom, duration) {
        var dateNowMinusDuration = moment.utc(dateTimeFrom);
        dateNowMinusDuration.subtract(Math.abs(duration), "seconds");
        return dateNowMinusDuration;
    }
    /**
         * @ngdoc method
         * @name RA.IPDisplay.service:timeseriesHelperSvc#filterAndSortData
         * @methodOf RA.IPDisplay.service:timeseriesHelperSvc
         * @description Function to filter duplicate data by timestamp and sort them.
         * @param {Array} data new timeseries data
         * @param {Integer} duration duration of timeseries data to watch in seconds
         * @returns {Array} filtered array data
         */
    this.filterAndSortData = function(data, endTime, duration) {
        var result = [];
        var dateNowMinusDuration = calculateTimeWithoutDuration(endTime, duration);
        var filteredData;
        angular.forEach(data, function(vqtArray, index) {
            if (vqtArray === null) {
                result[index] = null;
            } else {
                filteredData = vqtArray;
                filteredData.sort(sortSeriesData);
                filteredData = filterDataLocal(vqtArray, dateNowMinusDuration);
                result[index] = filteredData;
            }
        });
        return result;
    };
    /**
         * @ngdoc method
         * @name RA.IPDisplay.service:timeseriesHelperSvc#mergeTimeseriesData
         * @methodOf RA.IPDisplay.service:timeseriesHelperSvc
         * @description Function to merge live timeseries data into whole (previous) data. 
         * It does count with requested duration for timeseries and removes not needed data.
         * @param {Array} currentData array of current timeseries data (directly modified)
         * @param {Array} newData new timeseries data, can be only incremental data
         * @param {Integer} endTime datetime for current request end time in unix miliseconds 
         * @param {Integer} duration duration of timeseries data to watch in seconds
         * @return {Array} array with merged, filtered and sorted data
         */
    this.mergeTimeseriesData = function mergeTimeseriesData(currentData, newData, endTime, duration) {
        var result = [];
        if (!newData.length) {
            //just copy inner content of array into new one - always new reference
            angular.forEach(currentData, function(vqtArray, index) {
                result[index] = vqtArray;
            });
            return result;
        }
        var dateNowMinusDuration = calculateTimeWithoutDuration(endTime, duration);
        var mergedData;
        angular.forEach(currentData, function(vqtArray, index) {
            if (vqtArray === null) {
                result[index] = null;
            } else {
                if (newData[index][0]) {
                    // cut everything more then new data first timestamp
                    vqtArray = cutAfterDate(vqtArray, newData[index][0].timeStamp);
                }
                mergedData = vqtArray.concat(newData[index]);
                mergedData.sort(sortSeriesData);
                mergedData = filterDataLocal(mergedData, dateNowMinusDuration);
                result[index] = mergedData;
            }
        });
        return result;
    };
    /**
         * @ngdoc method
         * @module RA.IPDisplay
         * @name RA.IPDisplay.service:timeseriesHelperSvc#getTimeDeadBand
         * @methodOf RA.IPDisplay.service:timeseriesHelperSvc
         * @description Return calculated time dead band for the timeseries request.
         * @param {Number} duration in seconds to count deadband with
         * @param {Number} screenWidth width of screen
         * @param {Number} count - number of tags
         * @param {Boolean} noformat - when true return noformated number as seconds
         * @return {String|Nu,ber} time formatted string in format
         *         "HH:MM:SS.mmm", where HH is an hour 00-59, MM minute
         *         00-59, SS seconds 00-59 and mmm are milliseconds| number of seconds
         */
    this.getTimeDeadBand = function getTimeDeadBand(duration, screenWidth, count, noformat) {
        var tdb = Math.abs(duration) / (2 * screenWidth);
        var result = 0;
        if (!count) {
            if (tdb > 1) {
                result = tdb;
            }
            if (noformat) {
                return result;
            } else {
                return moment.duration(result, "seconds").format("d[:]hh[:]mm[:]ss[.]SSS", {
                    trim: false
                });
            }
        } else {
            var chunk = 0;
            //for 5 minutes we do not change anything
            if (Math.abs(duration) <= 300) {
                chunk = tdb;
            } else if (Math.abs(duration) <= 2592e3) {
                //for less than 30 days we multiply deadband by count of half of tags
                chunk = Math.abs(duration) / screenWidth * Math.ceil(count / 2);
            } else {
                //for more than 30 days we multiply deadband by count of tags
                chunk = Math.abs(duration) / screenWidth * count;
            }
            if (chunk > 1) {
                result = chunk;
            }
            if (noformat) {
                return result;
            } else {
                return moment.duration(result, "seconds").format("d[:]hh[:]mm[:]ss[.]SSS", {
                    trim: false
                });
            }
        }
    };
} ]);

