        result = result.replace(/#a349a4/g, "#916aad");
        result = result.replace(/#00a2e8/g, "#26a9e0");
        result = result.replace(/#3f48cc/g, "#0000ff");
        result = result.replace(/#b97a57/g, "#f5a25c");
